

<template>
<div class="audio_player container">
           <div class="row">
                <div class="col-sm-2"> <button id="prevbtn"></button></div>
                <div class="col-sm-2"><button id="playpausebtn" ></button></div>
                <div class="col-sm-2"><button id="nextbtn"></button></div>
                <div class="col-sm-2"><button id="mutebtn">   <input id="volumeslider" type="range" min="0" max="100" value="100" step="1"></button></div>
           </div>
      
        </div>
</template>

<script>

export default {
  name: 'AudioBtn'
}
</script>

<style lang="scss" scoped >

  // AUDIO PLAYER CSS

            .audio_player{
                position: absolute;
                bottom: 0px;
                background: #FFF;
                padding-left: 25vw;
                padding-top: 10px;
                left: 0px;
                border: solid black 1px;
                width: 100%;
                height: 80px;
                z-index: 0;
                    
            }

            /////////////////////////////////
        
            
          
            button {
                border: none;
                cursor: pointer;
                outline: none;
            }
            input{ 
                outline:none; 
            }
            button#playpausebtn {
                background: url(../../assets/img/icons8-play-50.png) no-repeat;
                width: 50px;
                height: 50px;
            }
            button.pauseImg{
                background: url(../../assets/img/icons8-pause.png) no-repeat !important;
                width: 50px;
                height: 50px;
            }
            button#mutebtn {
                background: url(../../assets/img/icons8-audio-50.png) no-repeat;
                width: 50px;
                height: 50px;
            }
            button.muteImg {
                background: url(../../assets/img/icons8-mute-50.png) no-repeat !important;
                width: 50px;
                height: 50px;
            }
            button#prevbtn {
                background: url(../../assets/img/icons8-fast-backward-50.png) no-repeat;
                width: 50px;
                height: 50px;
            }
            button#nextbtn {
                background: url(../../assets/img/icons8-fast-forward-50.png) no-repeat;
                width: 50px;
                height: 50px;
            }
            
         
            input#volumeslider{
                width: 15vw;
                margin-left: 170%;
            }
           
            input[type='range'] {
                -webkit-appearance: none !important;
                margin:0px;
                padding:0px;
                background: #000;
                height:13px;
                border-radius: 50px;
                border-bottom:#fff 1px solid;
            }
            input[type='range']::-ms-fill-lower  {
                background:#000;
            }
            input[type='range']::-ms-fill-upper  {
                background:#000;
            }
            input[type='range']::-moz-range-track {
                border:none;
                background: #000;
            }
            input[type='range']::-webkit-slider-thumb {
                -webkit-appearance: none !important;
                background: radial-gradient(#FFF, #333);
                height:11px;
                width:11px;
                border-radius:100%;
                cursor:pointer;
            }
            input[type='range']::-moz-range-thumb {
                background: radial-gradient(#FFF, #333);
                height:11px;
                width:11px;
                border-radius:100%;
                cursor:pointer;
            }
            input[type='range']::-ms-thumb {
                -webkit-appearance: none !important;
                background: radial-gradient(#FFF, #333);
                height:11px;
                width:11px;
                border-radius:100%;
                cursor:pointer;
            }


</style>




