<template>
  <div id="app">
    <!-- <router-link to="/">Home</router-link>
    <router-link to="/Study">Study</router-link>
    <router-link to="/About">About</router-link> -->
   <router-view />

  </div>
</template>

<script>

export default {
  name: 'app',
  data () {
    return {
      msg: 'Welcome to Your Vue.js App'
    }
  },
  created () {
    const userObj = JSON.parse(window.localStorage.getItem('authUser'))
    this.$store.dispatch('setUserObject', userObj)
  }
}
</script>

<style lang="scss">
#app {
  font-weight:300;

  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  color: #2c3e50;
  margin-top: -20px;
  background-color: rgba(241, 240, 240, 0.555);
}

section {
  height: 100vh;
}

div#sidebar:hover{
      width: 250px;
}
#mylist {

  max-height: 50vh;
  overflow-y: scroll;
  width: 100%;

  div.core-menu:hover {
    z-index: 999;

    .core-menu a {
      z-index: 999;
    }
  }
 

  .hd h1{
    border: solid black 1px;
    margin: 5px;
    margin-left: 0%;
    padding: 10px;
    left: 30%;
    font-size: 30px;
    
  } 


  .shrink h1{
      font-size: 20px;
      padding-top: 10px;
      height: 70px;
      
  }
  .pllist {
    max-height: 150px;
    overflow-y: scroll;
  }

 li {
      font-size: 20px;
      list-style-type: none;
      text-align: left;
      left: 10%;
      position: relative;
      width: 90%;
  }

}
</style>



