import Vue from 'vue'
import App from './App.vue'
import Home from './components/Home.vue'
import Growth from './components/Growth.vue'
import Events2 from './components/Events.vue'
import Events from './components/events2.vue'
import Contact from './components/Contact.vue'
import Member from './components/Member.vue'
import Location from './components/Location.vue'

import Audio from "./components/About.vue"

import VueRouter from 'vue-router'
import VueResource from 'vue-resource'
import Vuex from 'vuex'
import store from './store'
import quickMenu from 'vue-quick-menu'
import BootstrapVue from 'bootstrap-vue'
import VCalendar from 'v-calendar';
import 'v-calendar/lib/v-calendar.min.css';

////// Main
import Footer from "./components/main/Footer.vue"
import Nav from "./components/main/Nav.vue"

////// Home
  import Conviction from './components/home-sections/Conviction.vue'

  import Group from './components/home-sections/Group.vue'
  import Intro from './components/home-sections/Intro.vue'
  import Services from './components/home-sections/Services.vue'
  import Welcome from './components/home-sections/Welcome.vue'
  import Verses from './components/home-sections/Verses.vue'
  

/////// Growth
import AudioBtn from "./components/audio-player/AudioBtn.vue"
import Study from './components/growth-pages/Study.vue'
import Hymns from './components/growth-pages/Hymns.vue'
import Videos from './components/growth-pages/Videos.vue'

//////Member
import Dashboard from './components/member-pages/Dashboard.vue'



require('./assets/main.scss');


Vue.use(VueRouter)
Vue.use(VueResource)
Vue.use(BootstrapVue)
Vue.use(VCalendar, {

});

const routes = [
  { path:'/', component: Home},
  { path:'/growth', component: Growth },
  { path:'/events', component: Events },
  { path:'/events2', component: Events2 },  
  { path:'/member', component: Member, name: "member" },
  { path:'/member/dashboard', component: Dashboard , meta: {requiresAuth: true }},
  { path:'/location', component: Location },
  { path:'/contact', component: Contact },
  { path:'/growth/study', component: Study },
  { path:'/growth/hymns', component: Hymns },
  { path:'/growth/videos', component: Videos },
  
]

const router = new VueRouter({
  routes,
  mode: "history"
})

router.beforeEach((to, from, next) => {
  if(to.meta.requiresAuth){
    const authUser = JSON.parse(window.localStorage.getItem('authUser'))
    if(authUser && authUser.access_token){
      next()
    } else {
      next({path:'/member/dashboard'})
    }
  }
  next()
})

new Vue({
  el: '#app',
  router, store,
  render: h => h(App)
})



