<template>


    <div style="margin-top: 20px; ">
      <nav-component></nav-component>
      <div id="content">
         <div><h1 id="curtrack">SELECT TRACK</h1></div>
    
        <div id="timebox">
          <span id="curtimetext">00:00</span> / <span id="durtimetext">00:00</span>
          <div><input id="seekslider" type="range" min="0" max="100" value="0" step="1"></div>

        </div>
    
            <br>
            <div id="songs">        
                <input type="text" id="myInput" placeholder="Search for names.." title="Type in a name">
                <input type="text" class="search" placeholder="Search for names with list js" title="Type in a name">

            </div>
            
      <div id="mylist" class="list">
        
      </div>
       
        <audiobtn-component></audiobtn-component>
      </div>
    </div>
</template>

<script>
import Nav from '../main/Nav.vue';
import AudioBtn from '../audio-player/AudioBtn.vue';

export default {
  name: 'Study',
  data (){
      return {
      }
  },
  components: {
      'nav-component': Nav,
      'audiobtn-component': AudioBtn
  },
  methods: {
     getData: function(){ 
          this.$http.get('http://localhost:8080/src/assets/audio.json').then(response => {

              var audio,input, dir, ext, elementVal, elementPrev, elementNext, elementTxt, curtrack, playbtn, mutebtn, prevbtn, nextbtn, searchinput, seekslider, volumeslider, seeking, seekto, curtimetext, durtimetext, $this;
                    dir = "https://archive.org/download/mythium/";
                    ext = ".mp3";
                    input = this.search

                 //set object references
                    curtrack = document.getElementById("curtrack");
                    playbtn = document.getElementById("playpausebtn");
                    mutebtn = document.getElementById("mutebtn");
                    seekslider = document.getElementById("seekslider");
                    volumeslider = document.getElementById("volumeslider");
                    curtimetext = document.getElementById("curtimetext");
	                durtimetext = document.getElementById("durtimetext");
	                prevbtn = document.getElementById("prevbtn");
                    nextbtn = document.getElementById("nextbtn");
                    searchinput = document.getElementById("myInput");
                
                audio = new Audio();

                     $.each(response.data, function(key, value){
                 
                     for (var i=0; i < [key].length; i++){ 

                        $("#mylist").append( '<div class=" col-xs-12 col-sm-12 col-lg-8 col-lg-offset-2"><div class="hd"><h1 class="series">'+ key.replace(/_/g,' ').replace(/-/g,',') +'</h1></div><div class="pllist" id="title'+ [key] +'"></div>');
                        
                               }

                     for (var i=0; i < value.length; i++){

                        $("#title" + [key]).append( '<li value="'+ value[i].url+'" class="name">'+ value[i].name +'</li></div></div');   
                    
                        }
                        
                    })

                    $('.pllist').hide();

                        $('.hd').click(function(){
                            
                            $(this).next(".pllist").slideToggle('slow');
                            console.log("clicked")
                            // $(this).toggleClass("shrink");

                          
                      
                        });

                        $("#myInput").keyup(function(){
                    
                            $(".pllist").show();

                            if(!this.value){
                                $(".pllist").hide();
                            }

                        });
                         

                        $("#mylist li").click(function (){
                        
                            $this = $(this);
                        
                            elementVal =  $(this).attr('value');
                            elementPrev =  $(this).prev().attr('value');
                            elementNext = $(this).next().attr('value');
                        
                            elementTxt = $(this).html();
                            
                            audio.src = dir + elementVal + ext;
                            audio.play();                           
                
                            $(playbtn).addClass("pauseImg")
                            
                            seekslider.value = 0; 
                            
                            curtrack.innerHTML = elementTxt;

                        });
            //event listening
                        $(playbtn).click(function () {
                        
                        if(audio.paused) {
                            audio.play();
                            $(playbtn).addClass("pauseImg")
                        } else {
                            audio.pause();
                            $(playbtn).removeClass("pauseImg")
                        }
                            
                        })
                        $(mutebtn).click(function () {
                               if(audio.muted) {
                            audio.muted = false;
                            $(mutebtn).removeClass("muteImg")
                        } else {
                            audio.muted = true;
                            $(mutebtn).addClass("muteImg")
                        }
                            
                        })
                        $(prevbtn).click(function () {
                                if(elementPrev !== undefined) {
                            audio.src = dir + elementPrev + ext ;
                            audio.play();
                        } else {
                            audio.src = audio.src;
                            audio.play();
                        }
                            
                        })
                        $(nextbtn).click(function () {
                                   if(elementNext !== undefined){
                            audio.src = dir + elementNext + ext ;
                            audio.play();
                        } else {
                            audio.src = audio.src;
                            audio.play();
                        }
                            
                        })
                        $("#app a").click(function (){
                            audio.pause();
                        })
                        $(seekslider).mousedown(function (event) {
                            seeking = true; 
                            seek(event);
                        })
                        $(seekslider).mousemove(function (event) {
                            seek(event);
                        })
                        $(seekslider).mouseup(function () {
                            seeking = false;
                        })
                        $(volumeslider).mousemove(function () {
                            setVolume();
                        })
                        audio.addEventListener("timeupdate", function(){ seektimeupdate()});
                        
                        $(searchinput).keyup(function (){
                            searchFunction();
                        }) 

                     function seek(event){
                        if(seeking){
                            seekslider.value = event.clientX - seekslider.offsetLeft;
                            seekto = audio.duration * (seekslider.value / 100);
	                        audio.currentTime = seekto;
                        }
                    }
             /////////////////////////////////////////////
                    function setVolume(){
                        audio.volume = volumeslider.value / 100;
                    }
          ////////////////////////////////////////////////
                    function seektimeupdate(){
                        var nt = audio.currentTime * (100 / audio.duration);
                        seekslider.value = nt;
                        var curmins = Math.floor(audio.currentTime / 60);
                        var cursecs = Math.floor(audio.currentTime - curmins * 60);
                        var durmins = Math.floor(audio.duration / 60);
                        var dursecs = Math.floor(audio.duration - durmins * 60);
                    
                        
                            if(cursecs < 10){ cursecs = "0"+cursecs; }
                            if(dursecs < 10){ dursecs = "0"+dursecs; }
                            if(curmins < 10){ curmins = "0"+curmins; }
                            if(durmins < 10){ durmins = "0"+durmins; }
                        curtimetext.innerHTML = curmins+":"+cursecs;
                        durtimetext.innerHTML = durmins+":"+dursecs;
                    }
                    
                function searchFunction(){

                
                 var filter, div, title, li, h1, i, a, fil;

                    filter = searchinput.value.toUpperCase();
                    div = document.getElementById("mylist");
                    li = div.getElementsByTagName("li");  
                    h1 = div.getElementsByTagName("h1"); 

                   
         
               for (i = 0; i < li.length; i++) {
                      a = li[i];
                  
                    if (a.innerHTML.toUpperCase().indexOf(filter) > -1 ) {
                        li[i].style.display = "";
                        $(a).addClass("display")

                  

                    
                    } 
                    else {
                        li[i].style.display = "none";
                        $(a).removeClass("display")

                }
            }

            if ($(li).hasClass("display")){

                console.log()
            }

              
        }
      })       
     },
     listJS: function(){
         var options = {
            valueNames: [ 'name', 'series']
            };

            var userList = new List('songs', options);

     }
 
    },
    mounted(){
      this.getData()
  }
}


</script>

<style lang="scss" scoped>

          

            .display {
                display: block;
            }
            #content {
                text-align: center;
            }

            #curtrack {
                text-align: left;
                left: 150px;
                width:90%;
                padding-top: 10px;
                position: relative;
            }
            
            input#seekslider{
                width:80vw;
                position: relative;
                left: 0px;
                
            }
           
            div#timebox{
                display:inline-block;
                width:auto;
                text-align:center;
                color: #09F; 
                font-family: Arial, Helvetica, sans-serif;
                font-size:20px;
            }
            input[type='range'] {
                -webkit-appearance: none !important;
                margin:0px;
                padding:0px;
                background: #000;
                height:13px;
                border-radius: 50px;
                border-bottom:#fff 1px solid;
            }
            input[type='range']::-ms-fill-lower  {
                background:#000;
            }
            input[type='range']::-ms-fill-upper  {
                background:#000;
            }
            input[type='range']::-moz-range-track {
                border:none;
                background: #000;
            }
            input[type='range']::-webkit-slider-thumb {
                -webkit-appearance: none !important;
                background:aquamarine;
                height:23px;
                width:43px;
                border-radius:5px;
                cursor:pointer;
            }
            input[type='range']::-moz-range-thumb {
                background: radial-gradient(#FFF, #333);
                height:11px;
                width:11px;
                border-radius:50px;
                cursor:pointer;
            }
            input[type='range']::-ms-thumb {
                -webkit-appearance: none !important;
                background: radial-gradient(#FFF, #333);
                height:11px;
                width:11px;
                cursor:pointer;                
                border-radius:50px;

            }


      

</style>


