  }
}
</script>

<style lang="scss" scoped>
#tab1Content {
 display: block; 
 
}

#tab2Content, #tab3Content, #tab4Content, #tab5Content  {
 display: none; 

}
.active {
  transform: rotate(180deg) scale(1.4)!important;
  // transform: rotate(189deg)!important;
}
.tabcontent {
