}
// @import "compass/css3";

/// Mixin to place items on a circle
/// @author Hugo Giraudel
/// @author Ana Tudor
/// @param {Integer} $item-count - Number of items on the circle
/// @param {Length} $circle-size - Large circle size
/// @param {Length} $item-size - Single item size
@mixin on-circle($item-count, $circle-size, $item-size) {  
  position: relative;
  width:  $circle-size;
  height: $circle-size;
  border-radius: 50%;
  padding: 0; 
  list-style: none;
  
  > * {
    display: block;
    position: absolute;
    top:  50%; 
    left: 50%;
    margin: -($item-size / 2);
    width:  $item-size;
    height: $item-size;
  
    $angle: (360 / $item-count);
    $rot: 0;

    @for $i from 1 through $item-count {
      &:nth-of-type(#{$i}) {
        transform: rotate($rot * 1deg) translate($circle-size / 2) rotate($rot * -1deg);
      }

      $rot: $rot + $angle;
    }
  }
}

.circle-container {
  @include on-circle($item-count: 5, $circle-size: 20em, $item-size: 8em); 
  margin: 5em auto 0;
  border: solid 5px rgb(180, 180, 180);

  img { 
    // background-image: url("../../assets/img/intro/tabs/iconcircle-01-01.svg");
    // background-size: 125px;
    // background-position: 113px 118px;
    display: block; 
    border: none;
    background-color: none;
    max-width: 100%; 
    border-radius: 50%;
    // border: solid 5px tomato;
    transition: .5s;
    cursor: pointer;
     
    &:hover {
      filter: grayscale(0);
    }
  }
}


</style>


